152→function formatDate(iso?: string): string {
153→  if (!iso) return '';
154→  const d = new Date(iso);
155→  const day = String(d.getDate()).padStart(2, '0');
156→  const month = String(d.getMonth() + 1).padStart(2, '0');
157→  const year = d.getFullYear();
158→  return `${day}/${month}/${year}`;
159→}
