325→function MyOrdersStoryWrapper({
326→  isLoading = false,
327→  hasError = false,
328→  isEmpty = false,
329→  hasActiveFilters = false,
330→}: {
331→  isLoading?: boolean;
332→  hasError?: boolean;
333→  isEmpty?: boolean;
334→  hasActiveFilters?: boolean;
335→}) {
336→  useEffect(() => {
337→    if (hasError) {
338→      seedStoreError();
339→      return;
340→    }
341→    if (isLoading) {
342→      seedStoreLoading();
343→      return;
344→    }
345→    if (isEmpty) {
346→      seedStoreEmpty();
347→      return;
348→    }
349→    seedStoreLoaded();
