361→        iconRight={showFilter ? 'icon-filter-settings' : undefined}
362→        onPressRight={() => {}}
363→      />
364→
365→      {hasError && <ErrorState />}
366→
367→      {isLoading && <LoadingState />}
368→
369→      {!isLoading && !hasError && (
370→        <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
371→          {isEmpty ? (
372→            <EmptyState hasActiveFilters={hasActiveFilters} />
373→          ) : (
374→            <OrdersList orders={MOCK_ORDERS} />
375→          )}
376→        </ScrollView>
377→      )}
378→    </Box>
379→  );
380→}
