```typescript
export const BoxSafeArea = styled(SafeAreaView).attrs<BoxSafeAreaProps>(
  ({ edges, mode }) => ({
    edges: edges ?? ['top', 'bottom'],
    mode: mode ?? 'padding',
  }),
)<BoxSafeAreaProps>`
  flex: 1;
  width: 100%;
  height: 100%;
  align-items: ${({ align }) => align ?? 'flex-start'};
  justify-content: ${({ justify }) => justify ?? 'flex-start'};
  background-color: ${({ type, theme }) =>
    type
      ? backgroundOptions(type).bgColor
      : theme?.styleBackground?.default?.bgColor};
  opacity: ${({ type }) =>
    backgroundOptions(type).opacity ? backgroundOptions(type).opacity : 100};
`;
```

**TypeScript Interface:**
```typescript
export interface BoxSafeAreaProps {
  children?: ReactNode;
  justify?: JustifyContentType;
  align?: FlexAlignType;
  type?: 'default' | 'scrim' | 'secundary';
  edges?: Edge[];  // ['top', 'bottom'] by default, can be ['top'], ['left'], etc.
  mode?: 'padding' | 'margin';  // 'padding' by default
}
